final class IAPManager: NSObject {

    weak var delegate: IAPManagerDelegate?

    private var productsRequest: SKProductsRequest?
    private var productsById: [String: SKProduct] = [:]
    private var pendingCallbackId: String?
    private var pendingFetchCallbackId: String?
    private var pendingRestoreCallbackId: String?
    private var pendingPurchaseCallbackId: String?

    override init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }

    deinit {
        SKPaymentQueue.default().remove(self)
    }

    func fetchProducts(ids: [String], callbackId: String?) {
        guard let callbackId else { return }
        pendingFetchCallbackId = callbackId

        productsRequest?.cancel()
        productsRequest = SKProductsRequest(productIdentifiers: Set(ids))
        productsRequest?.delegate = self
        productsRequest?.start()
    }

    func purchase(productId: String, callbackId: String?) {
        guard let callbackId else { return }
        pendingPurchaseCallbackId = callbackId

        if let product = productsById[productId] {
            SKPaymentQueue.default().add(SKPayment(product: product))
        } else {
            fetchProducts(ids: [productId], callbackId: "__internal_fetch_then_purchase__")
            pendingCallbackId = callbackId
        }
    }

    func restore(callbackId: String?) {
        guard let callbackId else { return }
        pendingRestoreCallbackId = callbackId
        SKPaymentQueue.default().restoreCompletedTransactions()
    }

    private func finishCallback(_ callbackId: String?, _ result: Result<[String: Any], Error>) {
        guard let callbackId else { return }
        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            self.delegate?.iapManager(self, didFinish: callbackId, result: result)
        }
    }

    private func productToDict(_ p: SKProduct) -> [String: Any] {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.locale = p.priceLocale
        let priceString = formatter.string(from: p.price) ?? "\(p.price)"
        return [
            "productId": p.productIdentifier,
            "localizedTitle": p.localizedTitle,
            "localizedDescription": p.localizedDescription,
            "price": p.price,
            "priceString": priceString,
            "priceLocale": p.priceLocale.identifier
        ]
    }
}

extension IAPManager: SKProductsRequestDelegate {
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        for p in response.products { productsById[p.productIdentifier] = p }

        if pendingFetchCallbackId == "__internal_fetch_then_purchase__" {
            let originalCallbackId = pendingCallbackId
            pendingCallbackId = nil
            pendingFetchCallbackId = nil

            if let first = response.products.first {
                SKPaymentQueue.default().add(SKPayment(product: first))
            } else {
                finishCallback(originalCallbackId, .failure(NSError(domain: "IAP", code: 404, userInfo: [NSLocalizedDescriptionKey: "Product not found"])))
            }
            return
        }

        let callbackId = pendingFetchCallbackId
        pendingFetchCallbackId = nil

        let payload: [String: Any] = [
            "products": response.products.map { productToDict($0) },
            "invalidProductIds": response.invalidProductIdentifiers
        ]
        finishCallback(callbackId, .success(payload))
    }

    func request(_ request: SKRequest, didFailWithError error: Error) {
        if pendingFetchCallbackId == "__internal_fetch_then_purchase__" {
            let originalCallbackId = pendingCallbackId
            pendingCallbackId = nil
            pendingFetchCallbackId = nil
            finishCallback(originalCallbackId, .failure(error))
            return
        }

        let callbackId = pendingFetchCallbackId
        pendingFetchCallbackId = nil
        finishCallback(callbackId, .failure(error))
    }
}

extension IAPManager: SKPaymentTransactionObserver {
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for t in transactions {
            switch t.transactionState {
            case .purchased:
                let payload: [String: Any] = [
                    "status": "purchased",
                    "productId": t.payment.productIdentifier,
                    "transactionId": t.transactionIdentifier ?? "",
                    "originalTransactionId": t.original?.transactionIdentifier ?? "",
                    "date": (t.transactionDate?.timeIntervalSince1970 ?? 0)
                ]
                finishCallback(pendingPurchaseCallbackId, .success(payload))
                pendingPurchaseCallbackId = nil
                queue.finishTransaction(t)

            case .restored:
                let payload: [String: Any] = [
                    "status": "restored",
                    "productId": t.payment.productIdentifier,
                    "transactionId": t.transactionIdentifier ?? "",
                    "originalTransactionId": t.original?.transactionIdentifier ?? "",
                    "date": (t.transactionDate?.timeIntervalSince1970 ?? 0)
                ]
                finishCallback(pendingRestoreCallbackId, .success(payload))
                queue.finishTransaction(t)

            case .failed:
                let err = t.error ?? NSError(domain: "IAP", code: -1, userInfo: [NSLocalizedDescriptionKey: "Transaction failed"])
                finishCallback(pendingPurchaseCallbackId ?? pendingRestoreCallbackId, .failure(err))
                pendingPurchaseCallbackId = nil
                pendingRestoreCallbackId = nil
                queue.finishTransaction(t)

            case .deferred:
                let payload: [String: Any] = [
                    "status": "deferred",
                    "productId": t.payment.productIdentifier
                ]
                finishCallback(pendingPurchaseCallbackId, .success(payload))

            case .purchasing:
                break

            @unknown default:
                break
            }
        }
    }

    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        let payload: [String: Any] = [
            "status": "restore_finished",
            "restoredCount": queue.transactions.filter { $0.transactionState == .restored }.count
        ]
        finishCallback(pendingRestoreCallbackId, .success(payload))
        pendingRestoreCallbackId = nil
    }

    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        finishCallback(pendingRestoreCallbackId, .failure(error))
        pendingRestoreCallbackId = nil
    }
}

